const item = $input.first();
const emailData = item.json;
const maxChars = $('Set Context').item.json.max_content_chars || 5000;

// --- Sender ---
let senderEmail = '';
let senderName = '';
if (emailData.from?.value?.[0]) {
  senderEmail = emailData.from.value[0].address || '';
  senderName  = emailData.from.value[0].name || senderEmail;
} else if (emailData.from?.text) {
  const emailMatch = emailData.from.text.match(/<([^>]+)>/) || emailData.from.text.match(/([^\s]+@[^\s]+)/);
  senderEmail = emailMatch ? emailMatch[1] : emailData.from.text;
  const nameMatch = emailData.from.text.match(/^([^<]+)/);
  senderName = nameMatch ? nameMatch[1].trim().replace(/"/g, '') : senderEmail;
}

// --- Date ---
const receivedDate = new Date(emailData.date || emailData.receivedTime || Date.now());
const formattedDate = receivedDate.toLocaleString('en-US', {
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', hour12: true
});

// --- Content ---
let emailContent = '';
if (emailData.text) {
  emailContent = emailData.text;
} else if (emailData.html) {
  emailContent = emailData.html
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
} else {
  emailContent = emailData.body || emailData.textPlain || emailData.textHtml || '';
}
if (emailContent.length > maxChars) {
  emailContent = emailContent.substring(0, maxChars) + '... [truncated]';
}

// --- Message ID (dedup key) ---
const messageId = emailData.id || emailData.messageId || (`${senderEmail}_${receivedDate.getTime()}`);

return [{
  json: {
    message_id:     messageId,
    sender_name:    senderName,
    sender_email:   senderEmail,
    subject:        emailData.subject || '(No Subject)',
    content:        emailContent,
    received_at:    formattedDate,
    has_attachment: (emailData.attachments?.length > 0) ? 'Yes' : 'No',
    labels:         (emailData.labelIds || []).join(', ')
  }
}];

